@dataclass
class PreviewConfigGUI:
    """Auto-generated GUI wrapper for PreviewConfig"""
    _core_config: PreviewConfig = field(default_factory=PreviewConfig)

    sample_file: tk.StringVar = field(init=False)
    enable_live_preview: tk.BooleanVar = field(init=False)
    _sample_file: tk.StringVar = field(init=False)
    _sample_preview: np.ndarray = None
    preview_frame_number: tk.IntVar = field(init=False)

    def __post_init__(self):
        self.sample_file = tk.StringVar(value=self._core_config.sample_file)
        self.enable_live_preview = tk.BooleanVar(value=self._core_config.enable_live_preview)
        self._sample_file = tk.StringVar(value=self._core_config._sample_file)
        self._sample_preview: np.ndarray = None
        self.preview_frame_number = tk.IntVar(value=self._core_config.preview_frame_number)
    
    @property
    def sample_preview(self) -> np.ndarray:
        if self._sample_preview is None or self._sample_file.get() != self.sample_file.get():
            filepath = self.sample_file.get()
            if filepath.endswith(('.avi', '.mp4')):
                frames = []
                container = av.open(filepath)
                for frame in container.decode(video=0):
                    frames.append(frame.to_ndarray(format='gray'))
                file = np.array(frames)
                file = np.expand_dims(file, axis = 3) if len(file.shape) == 3 else file
            elif filepath.endswith(('.tif', '.tiff')):
                file = iio.imread(filepath)
                file = np.expand_dims(file, axis = 3) if len(file.shape) == 3 else file
                if file.shape[3] != min(file.shape):
                    file = np.swapaxes(np.swapaxes(file, 1, 2), 2, 3)
            elif filepath.endswith('.nd2'):
                with nd2.ND2File(filepath) as ndfile:
                    if (len(ndfile.sizes) < 5 and (not 'Z' in ndfile.sizes) and 
                        'T' in ndfile.sizes and len(ndfile.shape) > 2 and ndfile.sizes['T'] > 5):
                        file = ndfile.asarray()
                        file = np.expand_dims(file, axis = 1) if len(file.shape) == 3 else file
                        file = np.swapaxes(np.swapaxes(file, 1, 2), 2, 3)
            else:
                file = np.ones((3, 256, 256, 1))
            self._sample_preview = file
            self._sample_file.set(filepath)
        return self._sample_preview

    @property
    def config(self) -> PreviewConfig:
        """Get current config from GUI values"""
        return PreviewConfig(
            sample_file=self.sample_file.get(),
            enable_live_preview=self.enable_live_preview.get(),
            _sample_file=self._sample_file.get(),
            _sample_preview=self._sample_preview,
            preview_frame_number=self.preview_frame_number.get(),
        )

    def update_gui(self, new_config: PreviewConfig):
        """Update GUI from new config values"""
        self._core_config = new_config
        self.sample_file.set(new_config.sample_file)
        self.enable_live_preview.set(new_config.enable_live_preview)
        self._sample_file.set(new_config._sample_file)
        self._sample_preview = None
        self.preview_frame_number.set(new_config.preview_frame_number)

